/* Main computational kernel. The whole function will be timed,
   including the call and return. */
extern "C" void kernel_jacobi_1d(int tsteps,
                                 int n,
                                 std::vector<double>& A,
                                 std::vector<double>& B)
{
    const double inv3 = 1.0 / 3.0;

    /* Make local raw pointers for faster access */
    double* a = A.data();
    double* b = B.data();

    for (int t = 0; t < tsteps; ++t) {
        /* First half‑update: B[i] depends on A */
#       pragma omp parallel for schedule(static) if (n > 1)
        for (int i = 1; i < n - 1; ++i) {
            b[i] = inv3 * (a[i-1] + a[i] + a[i+1]);
        }

        /* Second half‑update: A[i] depends on B */
#       pragma omp parallel for schedule(static) if (n > 1)
        for (int i = 1; i < n - 1; ++i) {
            a[i] = inv3 * (b[i-1] + b[i] + b[i+1]);
        }
    }
}
