/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_trmm(int m, int n,
                 double alpha,
                 std::vector<std::vector<double>>& A,
                 std::vector<std::vector<double>>& B) {
    /* Form  B := alpha*A**T*B.
       A is MxM
       B is MxN
    */

    /* Parallelise over the outer loop on i (rows of B).  The inner
       loops are small enough that a static schedule gives the best
       balance on an 8‑thread machine.
    */
#pragma omp parallel for schedule(static)
    for (int i = 0; i < m; ++i) {
        // For each column of B
        for (int j = 0; j < n; ++j) {
            double tmp = 0.0;
            // Compute the dot product of the i‑th column of A with the j‑th column of B
            for (int k = i + 1; k < m; ++k) {
                tmp += A[k][i] * B[k][j];
            }
            B[i][j] = alpha * (B[i][j] + tmp);
        }
    }
}
