void kernel_lu(int n, std::vector<std::vector<double>>& A) {
    // Parallelise the outermost loop over i
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        // Row i pointer for faster access
        double* row_i = A[i].data();

        // First part – elements below the diagonal
        for (int j = 0; j < i; ++j) {
            double* row_j = A[j].data();

            // Evaluate the inner dot product
            double sum = 0.0;
            for (int k = 0; k < j; ++k) {
                sum += row_i[k] * row_j[k];
            }
            row_i[j] = (row_i[j] - sum) / row_j[j];
        }

        // Second part – elements on and above the diagonal
        for (int j = i; j < n; ++j) {
            double sum = 0.0;
            for (int k = 0; k < i; ++k) {
                sum += row_i[k] * A[k][j];
            }
            row_i[j] -= sum;
        }
    }
