// Floyd‑Warshall with cache‑friendly layout and OpenMP
// The function signature must match the harness.
void kernel_floyd_warshall(int n, std::vector<std::vector<int>>& path) {
    // Assume the matrix is rectangular: path[i].size() == n for all i.
    // Work with a flat 1‑D pointer for better cache usage.
    // We’ll treat the matrix in row‑major order: entry (i,j) -> data[i*n + j].
    int* flat = path[0].data();                 // base pointer
    const std::size_t stride = static_cast<std::size_t>(n);

    // The outer loop over k must stay sequential to preserve correctness.
    for (int k = 0; k < n; ++k) {
        // Parallelise the middle loop over i.
        // Each thread works on a distinct row slice, so no false sharing.
        #pragma omp parallel for
        for (int i = 0; i < n; ++i) {
            int* row_i = flat + static_cast<std::size_t>(i) * stride;
            const int* row_k = flat + static_cast<std::size_t>(k) * stride;
            const int tmp = row_k[k];                // path[k][k] (often 0)
            for (int j = 0; j < n; ++j) {
                // Compute path[i][k] + path[k][j] without virtual calls.
                const int new_val = row_i[k] + row_k[j];
                // Replace std::min with an inline branch.
                if (new_val < row_i[j]) {
                    row_i[j] = new_val;
                }
            }
        }
    }
}
