/* Main computational kernel. The whole function will be timed,
   including the call and return.  */
void kernel_cholesky(int n,
                     std::vector<std::vector<double>>& A)
{
    /* Use raw pointers for rows to get contiguous memory access
       and to allow compiler optimisations such as vectorisation.
       The outer loop is serial because of data dependencies.     */
    for (int i = 0; i < n; ++i)
    {
        double* Ai = A[i].data();          // current row

        /* --- Off‑diagonal elements (i, j) with j < i --- */
        for (int j = 0; j < i; ++j)
        {
            double* Aj = A[j].data();     // row j
            double sum = Ai[j];

            /* Inner loop: dot product of row i and row j up to j-1 */
            int k = 0;
            #pragma omp simd reduction(-:sum)
            for (; k <= j - 1; ++k)
                sum -= Ai[k] * Aj[k];

            /* Normalise by diagonal element of row j */
            Ai[j] = sum / Aj[j];
        }

        /* --- Diagonal element A[i][i] --- */
        double* Ai_diagonal_ptr = Ai + i;
        double sum = *Ai_diagonal_ptr;

        int k = 0;
        #pragma omp simd reduction(-:sum)
        for (; k <= i - 1; ++k)
            sum -= Ai[k] * Ai[k];

        *Ai_diagonal_ptr = std::sqrt(sum);
    }
}
