/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_doitgen(int nr, int nq, int np,
		    std::vector<std::vector<std::vector<double>>>& A,
		    std::vector<std::vector<double>>& C4,
		    std::vector<double>& sum) {

    // Ensure the temporary buffer has a stable address across threads.
    double* sum_buf = sum.data();

    /* Parallelise over the two outermost loops.
       collapse(2) lets the scheduler make larger chunks and keeps the
       memory hierarchy intact.  The innermost work is small but still
       benefits from multi‑threading when nr·nq is large. */
    #pragma omp parallel for collapse(2) schedule(static)
    for (int r = 0; r < nr; ++r) {
        for (int q = 0; q < nq; ++q) {
            // Working with raw pointers for the innermost loops gives
            // the compiler more freedom for vectorisation and cache use.
            const double* a_row = A[r][q].data();          // A[r][q][s]
            double*       a_out = A[r][q].data();          // destination
            const double* c4    = C4[0].data();            // C4[s][p] layout

            for (int p = 0; p < np; ++p) {
                double acc = 0.0;
                const double* a_col = a_row;   // pointer to A[r][q][0]
                const double* c4_col = c4 + p; // pointer to C4[0][p]
                for (int s = 0; s < np; ++s) {
                    acc += a_col[s] * c4_col[s*np];
                }
                sum_buf[p] = acc;
            }

            // Copy the accumulated values back to the matrix A
            std::memcpy(a_out, sum_buf, np * sizeof(double));
        }
    }
}
