/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_jacobi_2d(int tsteps,
		      int n,
		      std::vector<std::vector<double>>& A,
		      std::vector<std::vector<double>>& B) {
    // Flattened access for better cache performance
    const int stride = n;
    double *ptrA = &A[0][0];
    double *ptrB = &B[0][0];

    // Precompute multipliers
    const double coef = 0.2;
    for (int t = 0; t < tsteps; ++t) {
        // Update B from A
        #pragma omp parallel for collapse(2) schedule(static)
        for (int i = 1; i < n - 1; ++i) {
            for (int j = 1; j < n - 1; ++j) {
                int idx = i * stride + j;
                ptrB[idx] = coef * (ptrA[idx]               // center
                                    + ptrA[idx - 1]         // west
                                    + ptrA[idx + 1]         // east
                                    + ptrA[idx + stride]    // south
                                    + ptrA[idx - stride]); // north
            }
        }

        // Update A from B
        #pragma omp parallel for collapse(2) schedule(static)
        for (int i = 1; i < n - 1; ++i) {
            for (int j = 1; j < n - 1; ++j) {
                int idx = i * stride + j;
                ptrA[idx] = coef * (ptrB[idx]               // center
                                    + ptrB[idx - 1]         // west
                                    + ptrB[idx + 1]         // east
                                    + ptrB[idx + stride]    // south
                                    + ptrB[idx - stride]); // north
            }
        }
    }
}
