/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_durbin(int n,
                   std::vector<double>& r,
                   std::vector<double>& y)
{
    // Local temporary array
    std::vector<double> z(n, 0.0);

    // Initial values
    y[0] = -r[0];
    double beta  = 1.0;
    double alpha = -r[0];

    double *const rptr = r.data();
    double *const yptr = y.data();
    double *const zptr = z.data();

    for (int k = 1; k < n; ++k) {
        // Update beta
        beta = (1.0 - alpha * alpha) * beta;

        // Compute sum = Σ_{i=0}^{k-1} r[k-1-i] * y[i]
        double sum = 0.0;
        const double *rk = rptr + k - 1;   // points to r[k-1]
        double *yp = yptr;
        for (int i = 0; i < k; ++i) {
            sum += *rk-- * *yp++;
        }

        // New reflection coefficient
        alpha = -(rptr[k] + sum) / beta;

        // Compute new y[0..k-1] into z
        yp = yptr;
        double *zq = zptr;
        double *yk = yptr + k - 1;
        for (int i = 0; i < k; ++i) {
            *zq++ = *yp++ + alpha * *yk--;
        }

        // Copy z[0..k-1] back to y[0..k-1]
        std::memcpy(yp - k, zptr, k * sizeof(double));

        // Final element
        yptr[k] = alpha;
    }
}
