// Helper to represent a matrix in a single contiguous block
struct Matrix {
  double* data;
  int rows, cols;

  Matrix(int r, int c) : rows(r), cols(c) {
    data = new double[rows * cols];
  }
  ~Matrix() { delete[] data; }

  double& operator()(int i, int j) { return data[i * cols + j]; }
  const double& operator()(int i, int j) const { return data[i * cols + j]; }
};

static Matrix* flatten(std::vector<std::vector<double>>& vecMat, int r, int c) {
  Matrix* mat = new Matrix(r, c);
  for (int i = 0; i < r; ++i)
    std::memcpy(mat->data + i * c, vecMat[i].data(), c * sizeof(double));
  return mat;
}

static void unflatten(Matrix* mat, std::vector<std::vector<double>>& vecMat) {
  for (int i = 0; i < mat->rows; ++i)
    std::memcpy(vecMat[i].data(), mat->data + i * mat->cols, mat->cols * sizeof(double));
}

void kernel_gemm(int ni, int nj, int nk,
                 double alpha,
                 double beta,
                 std::vector<std::vector<double>>& A,
                 std::vector<std::vector<double>>& B,
                 std::vector<std::vector<double>>& C) {

  // Flatten the matrices
  Matrix* matA = flatten(A, ni, nk);
  Matrix* matB = flatten(B, nk, nj);
  Matrix* matC = flatten(C, ni, nj);

  // Parallel outer loop over i with static scheduling
  #pragma omp parallel for schedule(static)
  for (int i = 0; i < ni; ++i) {
    double* Crow = matC->data + i * matC->cols;
    const double* Arow = matA->data + i * matA->cols;

    // C[i][j] *= beta
    for (int j = 0; j < nj; ++j)
      Crow[j] *= beta;

    // C += alpha * A * B
    for (int k = 0; k < nk; ++k) {
      double aik = alpha * Arow[k];
      const double* Brows = matB->data + k * matB->cols;
      for (int j = 0; j < nj; ++j)
        Crow[j] += aik * Brows[j];
    }
  }

  // Copy result back to C
  unflatten(matC, C);

  // Clean up
  delete matA;
  delete matB;
  delete matC;
}
