void kernel_gramschmidt(int m, int n,
                        std::vector<std::vector<double>>& A,
                        std::vector<std::vector<double>>& R,
                        std::vector<std::vector<double>>& Q)
{
    // Use OpenMP for inner parallelism only. The outer loop over k is sequential
    // because the algorithm is inherently sequential.
    for (int k = 0; k < n; ++k) {
        /* Compute the norm of column k of A */
        double nrm = 0.0;
#pragma omp parallel for reduction(+:nrm) schedule(static)
        for (int i = 0; i < m; ++i)
            nrm += A[i][k] * A[i][k];
        R[k][k] = std::sqrt(nrm);

        /* Normalize column k to form Q */
#pragma omp parallel for schedule(static)
        for (int i = 0; i < m; ++i)
            Q[i][k] = A[i][k] / R[k][k];

        /* Process remaining columns j > k */
#pragma omp parallel for schedule(static)
        for (int j = k + 1; j < n; ++j) {
            double rij = 0.0;

            // Compute inner product of Q[:,k] and A[:,j]
#pragma omp parallel for reduction(+:rij) schedule(static)
            for (int i = 0; i < m; ++i)
                rij += Q[i][k] * A[i][j];

            R[k][j] = rij;

            // Orthogonalize column j against Q[:,k]
#pragma omp parallel for schedule(static)
            for (int i = 0; i < m; ++i)
                A[i][j] -= Q[i][k] * rij;
        }
    }
}
