/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_ludcmp(int n,
                   std::vector<std::vector<double>>& A,
                   std::vector<double>& b,
                   std::vector<double>& x,
                   std::vector<double>& y)
{
    /* LU decomposition with partial pivoting (no pivoting here, as in the original) */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double* Ai = A[i].data();

        /* U‑part below the diagonal */
        for (int j = 0; j < i; ++j) {
            double w = Ai[j];
            double* Ak = A[i].data();
            double* Akj = A[j].data();
            for (int k = 0; k < j; ++k) {
                w -= Ak[k] * Akj[k];
            }
            Ai[j] = w / Akj[j];
        }

        /* U‑part on/above the diagonal */
        for (int j = i; j < n; ++j) {
            double w = Ai[j];
            double* Ak = A[i].data();
            double* Aj = A[j].data();
            for (int k = 0; k < i; ++k) {
                w -= Ak[k] * Aj[k];
            }
            Ai[j] = w;
        }
    }

    /* Forward substitution: solve Ly = b */
    for (int i = 0; i < n; ++i) {
        double w = b[i];
        double* Ai = A[i].data();
        for (int j = 0; j < i; ++j) {
            w -= Ai[j] * y[j];
        }
        y[i] = w;
    }

    /* Backward substitution: solve Ux = y */
    for (int i = n - 1; i >= 0; --i) {
        double w = y[i];
        double* Ai = A[i].data();
        for (int j = i + 1; j < n; ++j) {
            w -= Ai[j] * x[j];
        }
        x[i] = w / Ai[i];
    }
}
