/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_symm(int m, int n,
                 double alpha,
                 double beta,
                 std::vector<std::vector<double>>& C,
                 std::vector<std::vector<double>>& A,
                 std::vector<std::vector<double>>& B)
{
    // Get raw pointers to avoid vector bounds checks inside the hot loops
    MatrixData Cd = get_matrix_data(C);
    MatrixData Ad = get_matrix_data(A);
    MatrixData Bd = get_matrix_data(B);

    const double  *A_i   = Ad.data;   // will be advanced row by row
    const double  *B_i   = Bd.data;
    double       *C_i   = Cd.data;

    const int strideC = Cd.stride;
    const int strideA = Ad.stride;
    const int strideB = Bd.stride;

    // Parallelise the outer two loops. The work is perfectly independent.
    #pragma omp parallel for schedule(static, omp_get_num_threads())
    for (int i = 0; i < m; ++i) {
        const double *A_row_i = A_i + i * strideA;      // row i of A
        const double *B_row_i = B_i + i * strideB;      // row i of B
        const double   A_ii   = A_row_i[i];             // A[i][i]

        double *C_row_i = C_i + i * strideC;            // row i of C

        for (int j = 0; j < n; ++j) {
            double temp2 = 0.0;
            const double   B_ij = B_row_i[j];
            double *C_ij = C_row_i + j;

            // Loop over k < i (the lower triangle part of A)
            for (int k = 0; k < i; ++k) {
                const double   A_ik = A_row_i[k];      // A[i][k]
                const double B_kj = B_i + k * strideB;
                B_kj += j; // B[k][j]

                *C_ij += alpha * B_ij * A_ik;
                temp2 += *(B_kj) * A_ik;
            }

            *C_ij = beta * (*C_ij) + alpha * B_ij * A_ii + alpha * temp2;
        }
    }
