inline void kernel_seidel_2d(int tsteps,
                             int n,
                             std::vector<std::vector<double>>& A) {
    // Flatten the 2‑D vector into a 1‑D array for better cache usage
    const int N = n * n;
    std::vector<double> flat(N);
    for (int i = 0; i < n; ++i)
        std::copy(A[i].begin(), A[i].end(), flat.begin() + i * n);

    const double inv9 = 1.0 / 9.0;
    for (int t = 0; t < tsteps; ++t) {
        // We update in place; the same flat array is used for reading and writing
        for (int i = 1; i <= n - 2; ++i) {
            const int row = i * n;
            const int prev_row = (i - 1) * n;
            const int next_row = (i + 1) * n;
            for (int j = 1; j <= n - 2; ++j) {
                flat[row + j] = (flat[prev_row + j - 1] + flat[prev_row + j] + flat[prev_row + j + 1] +
                                 flat[row + j - 1] + flat[row + j] + flat[row + j + 1] +
                                 flat[next_row + j - 1] + flat[next_row + j] + flat[next_row + j + 1]) * inv9;
            }
        }
    }

    // Copy the flattened result back into the original 2‑D structure
    for (int i = 0; i < n; ++i)
        std::copy(flat.begin() + i * n, flat.begin() + (i + 1) * n, A[i].begin());
