       each thread keeps its own temporary buffer and later
       aggregates the result. */
    int num_threads = omp_get_max_threads();
    std::vector<std::vector<double>> localS(num_threads, std::vector<double>(m, 0.0));

    #pragma omp parallel
    {
        int tid = omp_get_thread_num();
        std::vector<double>& ts = localS[tid];

        #pragma omp for schedule(static)
        for (int i = 0; i < n; ++i) {
            double ri = r[i];
            /* Temporary accumulator for q[i] */
            double qi = 0.0;
            const std::vector<double>& Ai = A[i];

