// ---------------------------------------------------------------------
// Optimised correlation kernel
// ---------------------------------------------------------------------
void kernel_correlation(int m, int n,
                        std::vector<std::vector<double>>& data,
                        std::vector<std::vector<double>>& corr,
                        std::vector<double>& mean,
                        std::vector<double>& stddev) {
    const double eps = 0.1;
    const double sqrt_n = std::sqrt(static_cast<double>(n));

    // -------------------------------------------------
    // 1) Compute means and variances in a single pass
    // -------------------------------------------------
    mean.assign(m, 0.0);
    stddev.assign(m, 0.0);

    // Parallel over columns; each thread works on a contiguous block of rows
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < m; ++j) {
        double sum = 0.0;
        for (int i = 0; i < n; ++i) {
            sum += data[i][j];
        }
        mean[j] = sum / n;
    }

    // Variance
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < m; ++j) {
        double var = 0.0;
        for (int i = 0; i < n; ++i) {
            double diff = data[i][j] - mean[j];
            var += diff * diff;
        }
        var /= n;
        stddev[j] = std::sqrt(var);
        // Guard against near‑zero std‑dev
        if (stddev[j] <= eps) stddev[j] = 1.0;
    }

    // -------------------------------------------------
    // 2) Standardise the data matrix
    // -------------------------------------------------
    // Standardise in-place: subtract mean, divide by (sqrt(n)*stddev)
    #pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < m; ++j) {
            data[i][j] = (data[i][j] - mean[j]) / (sqrt_n * stddev[j]);
        }
    }

    // -------------------------------------------------
    // 3) Compute correlation matrix
    // -------------------------------------------------
    // Because data[i][j] is already standardised, cor(i,j)=Σ data[k][i]*data[k][j]
    // Parallelise outer loop over i
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < m; ++i) {
        corr[i][i] = 1.0;                // diagonal elements
        for (int j = i + 1; j < m; ++j) {
            double sum = 0.0;
            for (int k = 0; k < n; ++k) {
                sum += data[k][i] * data[k][j];
            }
            corr[i][j] = sum;
            corr[j][i] = sum;            // symmetry
        }
    }
}
