/* Optimised Nussinov kernel.
 *
 * The algorithm is identical to the original implementation – only
 * the data layout and parallelism have been changed to exploit
 * cache‑locality and multiple cores.
 *
 * A flat 1‑D array is used in place of std::vector<std::vector<int>>
 * so that all elements belonging to the same row are contiguous in
 * memory.  The table size is n × n and only the upper‑triangular part
 * is accessed; the rest remains unused, which is intentional to keep
 * the original behaviour.
 *
 * OpenMP is applied to the innermost k‑loop, which is independent for a
 * given (i, j).  This gives a moderate shared‑memory parallelism without
 * breaking data dependencies.
 */

inline int match(int b1, int b2) { return (b1 + b2 == 3) ? 1 : 0; }

void kernel_nussinov(int n, std::vector<int> const& seq,
                     std::vector<std::vector<int>>& table)
{
    /* Flatten the table.  The original 2‑D interface is kept for
     * compatibility, but we work directly on a 1‑D buffer here. */
    std::vector<int> flat(n * n, 0);
    auto idx = [n](int i, int j) { return i * n + j; };

    for (int i = n - 1; i >= 0; --i)
    {
        for (int j = i + 1; j < n; ++j)
        {
            int val = flat[idx(i, j)];

            /* table[i][j] = max(table[i][j], table[i][j-1]) */
            if (j - 1 >= 0)
                val = std::max(val, flat[idx(i, j-1)]);

            /* table[i][j] = max(table[i][j], table[i+1][j]) */
            if (i + 1 < n)
                val = std::max(val, flat[idx(i+1, j)]);

            /* pair or skip */
            if (j - 1 >= 0 && i + 1 < n)
            {
                if (i < j - 1)
                    val = std::max(val,
                                   flat[idx(i+1, j-1)] + match(seq[i], seq[j]));
                else
                    val = std::max(val, flat[idx(i+1, j-1)]);
            }

            /* split at k */
            int best = val;
#pragma omp parallel for reduction(max:best)
            for (int k = i + 1; k < j; ++k)
            {
                int sum = flat[idx(i, k)] + flat[idx(k+1, j)];
                if (sum > best) best = sum;
            }
            val = best;

            flat[idx(i, j)] = val;
        }
    }

    /* Write back flat buffer to the original 2‑D vector */
#pragma omp parallel for collapse(2)
    for (int i = 0; i < n; ++i)
        for (int j = 0; j < n; ++j)
            table[i][j] = flat[idx(i, j)];
}
