                    double sum    = c * (A_ip1[j][k] - 2.0 * center + A_im1[j][k])
                                   + c * (A_i[j+1][k] - 2.0 * center + A_i[j-1][k])
                                   + c * (A_i[j][k+1] - 2.0 * center + A_i[j][k-1])
                                   + center;
                    B_i[j][k] = sum;
                }
            }
        }

        /* Parallel 3D loop that updates A from B */
        #pragma omp parallel for collapse(3) schedule(static)
        for (int i = 1; i <= imax; ++i) {
            for (int j = 1; j <= jmax; ++j) {
                const std::vector<double>& B_i   = B[i];
                const std::vector<double>& B_im1 = B[i-1];
                const std::vector<double>& B_ip1 = B[i+1];
                const std::vector<double>& A_i   = A[i];

                for (int k = 1; k <= kmax; ++k) {
                    double center = B_i[j][k];
                    double sum    = c * (B_ip1[j][k] - 2.0 * center + B_im1[j][k])
                                   + c * (B_i[j+1][k] - 2.0 * center + B_i[j-1][k])
                                   + c * (B_i[j][k+1] - 2.0 * center + B_i[j][k-1])
                                   + center;
                    A_i[j][k] = sum;
                }
            }
        }
    }
