    const std::size_t N = static_cast<std::size_t>(n);
    const std::size_t size = N * N;
    std::vector<double> u_buf(size);
    std::vector<double> v_buf(size);
    std::vector<double> p_buf(size);
    std::vector<double> q_buf(size);

    /* Helper to index the flattened arrays. */
    auto idx = [n](int i, int j) -> std::size_t { return static_cast<std::size_t>(i) * n + j; };

    /* Copy initial data into the buffers. */
    for (int i = 0; i < n; ++i)
        for (int j = 0; j < n; ++j)
        {
            u_buf[idx(i,j)] = u[i][j];
            v_buf[idx(i,j)] = v[i][j];
            p_buf[idx(i,j)] = p[i][j];
            q_buf[idx(i,j)] = q[i][j];
        }

    /* Pre‑compute constants. */
    const double DX = 1.0 / n;
    const double DY = 1.0 / n;
    const double DT = 1.0 / tsteps;
    const double B1 = 2.0;
    const double B2 = 1.0;
    const double mul1 = B1 * DT / (DX * DX);
    const double mul2 = B2 * DT / (DY * DY);
    const double a   = -mul1 / 2.0;
    const double b   = 1.0 + mul1;
    const double c   = a;
    const double d   = -mul2 / 2.0;
    const double e   = 1.0 + mul2;
    const double f   = d;

    /* Main time loop – parallelise the outer spatial loops. */
    for (int t = 1; t <= tsteps; ++t)
    {
        /* First sweep: horizontal solve for v */
        #pragma omp parallel for schedule(static,1) collapse(1)
        for (int i = 1; i < n - 1; ++i)
        {
            v_buf[idx(0,i)] = 1.0;
            p_buf[idx(i,0)] = 0.0;
            q_buf[idx(i,0)] = v_buf[idx(0,i)];

            for (int j = 1; j < n - 1; ++j)
            {
                double denom = a * p_buf[idx(i,j-1)] + b;
                p_buf[idx(i,j)] = -c / denom;
                double val = (-d * u_buf[idx(j,i-1)] + (1.0 + 2.0 * d) * u_buf[idx(j,i)] - f * u_buf[idx(j,i+1)] - a * q_buf[idx(i,j-1)]) / denom;
                q_buf[idx(i,j)] = val;
            }

            v_buf[idx(n-1,i)] = 1.0;
            for (int j = n - 2; j >= 1; --j)
                v_buf[idx(j,i)] = p_buf[idx(i,j)] * v_buf[idx(j+1,i)] + q_buf[idx(i,j)];
        }

        /* Second sweep: vertical solve for u */
        #pragma omp parallel for schedule(static,1) collapse(1)
        for (int i = 1; i < n - 1; ++i)
        {
            u_buf[idx(i,0)] = 1.0;
            p_buf[idx(i,0)] = 0.0;
            q_buf[idx(i,0)] = u_buf[idx(i,0)];

            for (int j = 1; j < n - 1; ++j)
