#include <cmath>
#include <vector>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_deriche(int w, int h, double alpha,
        std::vector<std::vector<float>>& imgIn,
        std::vector<std::vector<float>>& imgOut,
        std::vector<std::vector<float>>& y1,
        std::vector<std::vector<float>>& y2)
{
    /* Pre‑compute constants (the same formulas as in the original). */
    const float exp_a = std::exp(-alpha);
    const float exp_2a = exp_a * exp_a;
    const float k = 1.0f - exp_a * (1.0f - exp_a) /
                    (1.0f + 2.0f * alpha * exp_a - exp_2a);

    const float a1 = k, a5 = k;
    const float a2 = k * exp_a * (alpha - 1.0f), a6 = a2;
    const float a3 = k * exp_a * (alpha + 1.0f), a7 = a3;
    const float a4 = -k * exp_2a,            a8 = a4;
    const float b1 = std::pow(2.0f, -alpha);
    const float b2 = -exp_2a;
    const float c1 = 1.0f, c2 = 1.0f;    // unchanged

    /* --------------------------------------------------------------------- */
    /* 1. Forward scan – rows (horizontal filter)                          */
    /* --------------------------------------------------------------------- */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < w; ++i) {
        float ym1 = 0.0f, ym2 = 0.0f;
        float xm1 = 0.0f;
        const float* inRow  = imgIn[i].data();
        float*       yRow   = y1[i].data();
        for (int j = 0; j < h; ++j) {
            float val = a1 * inRow[j] + a2 * xm1 + b1 * ym1 + b2 * ym2;
            yRow[j] = val;
            xm1 = inRow[j];
            ym2 = ym1;
            ym1 = val;
        }
    }

    /* --------------------------------------------------------------------- */
    /* 2. Backward scan – rows (horizontal filter)                          */
    /* --------------------------------------------------------------------- */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < w; ++i) {
        float yp1 = 0.0f, yp2 = 0.0f;
        float xp1 = 0.0f, xp2 = 0.0f;
        const float* inRow = imgIn[i].data();
        float*       yRow  = y2[i].data();

        for (int j = h - 1; j >= 0; --j) {
            float val = a3 * xp1 + a4 * xp2 + b1 * yp1 + b2 * yp2;
            yRow[j] = val;
            xp2 = xp1;
            xp1 = inRow[j];
            yp2 = yp1;
            yp1 = val;
        }
    }

    /* --------------------------------------------------------------------- */
    /* 3. Combine horizontal results into imgOut (intermediate sum)          */
    /* --------------------------------------------------------------------- */
    #pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < w; ++i) {
        for (int j = 0; j < h; ++j) {
            imgOut[i][j] = c1 * (y1[i][j] + y2[i][j]);
        }
    }

    /* --------------------------------------------------------------------- */
    /* 4. Forward scan – columns (vertical filter)                           */
    /* --------------------------------------------------------------------- */
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < h; ++j) {
        float tm1 = 0.0f, ym1 = 0.0f, ym2 = 0.0f;
        for (int i = 0; i < w; ++i) {
            float val = a5 * imgOut[i][j] + a6 * tm1 + b1 * ym1 + b2 * ym2;
            y1[i][j] = val;
            tm1 = imgOut[i][j];
            ym2 = ym1;
            ym1 = val;
        }
    }

    /* --------------------------------------------------------------------- */
    /* 5. Backward scan – columns (vertical filter)                          */
    /* --------------------------------------------------------------------- */
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < h; ++j) {
        float tp1 = 0.0f, tp2 = 0.0f;
        float yp1 = 0.0f, yp2 = 0.0f;
        for (int i = w - 1; i >= 0; --i) {
            float val = a7 * tp1 + a8 * tp2 + b1 * yp1 + b2 * yp2;
            y2[i][j] = val;
            tp2 = tp1;
            tp1 = imgOut[i][j];
            yp2 = yp1;
            yp1 = val;
        }
    }

    /* --------------------------------------------------------------------- */
    /* 6. Final combination – write result back to imgOut                    */
    /* --------------------------------------------------------------------- */
    #pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < w; ++i) {
        for (int j = 0; j < h; ++j) {
            imgOut[i][j] = c2 * (y1[i][j] + y2[i][j]);
        }
    }
}
